import React, { useState, useEffect } from 'react';
import api from '../services/api';
import { useAuth } from '../context/AuthContext';

const Casino = () => {
  const [games, setGames] = useState([]);
  const [selectedGame, setSelectedGame] = useState(null);
  const [betAmount, setBetAmount] = useState(10);
  const [selection, setSelection] = useState('');
  const [result, setResult] = useState(null);
  const [playing, setPlaying] = useState(false);
  const { fetchBalance } = useAuth();

  useEffect(() => {
    loadGames();
  }, []);

  const loadGames = async () => {
    try {
      const res = await api.get('/api/casino/games');
      setGames(res.data);
    } catch (err) {
      console.error('Erro ao carregar jogos');
    }
  };

  const playGame = async () => {
    if (!selectedGame || betAmount <= 0) return;
    setPlaying(true);
    setResult(null);
    try {
      const res = await api.post('/api/casino/play', {
        gameId: selectedGame.id,
        betAmount: parseFloat(betAmount),
        selection: selection || undefined,
      });
      setTimeout(() => {
        setResult(res.data);
        fetchBalance();
        setPlaying(false);
      }, 2000);
    } catch (err) {
      setResult({ message: err.response?.data?.message || 'Erro ao jogar' });
      setPlaying(false);
    }
  };

  const getGameThemeColor = (game) => {
    if (game.theme === 'tiger') return '#ff9800';
    if (game.theme === 'ox') return '#f44336';
    if (game.theme === 'mouse') return '#9e9e9e';
    if (game.theme === 'dragon') return '#4caf50';
    if (game.theme === 'ganesha') return '#ffeb3b';
    return '#FFD700';
  };

  const styles = {
    container: { maxWidth: '1200px', margin: '0 auto', padding: '20px' },
    title: { fontFamily: "'Orbitron', sans-serif", fontSize: '32px', fontWeight: 700, marginBottom: '8px', textAlign: 'center' },
    subtitle: { textAlign: 'center', color: '#b0b0b0', marginBottom: '32px', fontSize: '15px' },
    grid: { display: 'grid', gridTemplateColumns: 'repeat(auto-fit, minmax(180px, 1fr))', gap: '20px', marginBottom: '40px' },
    gameCard: (game, isSelected) => ({
      background: isSelected ? `linear-gradient(135deg, ${getGameThemeColor(game)}33, #1a1a1a)` : '#1a1a1a',
      border: isSelected ? `2px solid ${getGameThemeColor(game)}` : '1px solid #2a2a2a',
      borderRadius: '20px', padding: '20px', textAlign: 'center', cursor: 'pointer',
      transition: 'all 0.3s ease', position: 'relative', overflow: 'hidden',
      transform: isSelected ? 'translateY(-5px)' : 'none'
    }),
    gameIcon: { fontSize: '50px', marginBottom: '15px', display: 'block' },
    gameName: { fontFamily: "'Orbitron', sans-serif", fontSize: '14px', fontWeight: 700, color: '#fff', marginBottom: '5px' },
    gameCategory: { fontSize: '10px', color: '#FFD700', fontWeight: 800, textTransform: 'uppercase' },
    playArea: (game) => ({
      background: '#1a1a1a', border: `1px solid ${getGameThemeColor(game)}`, borderRadius: '24px',
      padding: '40px', marginTop: '20px', textAlign: 'center', position: 'relative'
    }),
    reelsContainer: { display: 'flex', justifyContent: 'center', gap: '15px', margin: '30px 0' },
    reel: { width: '80px', height: '100px', background: '#0a0a0a', border: '2px solid #333', borderRadius: '12px', display: 'flex', alignItems: 'center', justifyContent: 'center', fontSize: '40px' },
    betControls: { display: 'flex', justifyContent: 'center', gap: '10px', marginBottom: '20px', flexWrap: 'wrap' },
    betBtn: (active) => ({
      padding: '10px 20px', borderRadius: '10px', border: 'none', cursor: 'pointer',
      background: active ? '#FFD700' : '#2a2a2a', color: active ? '#000' : '#fff', fontWeight: 700
    })
  };

  return (
    <div style={styles.container}>
      <h1 style={styles.title}>🎰 <span className="gold-text">W.M CASINO</span></h1>
      <p style={styles.subtitle}>Os melhores jogos estilo PG com multiplicadores insanos!</p>

      <div style={styles.grid}>
        {games.map(game => (
          <div key={game.id} style={styles.gameCard(game, selectedGame?.id === game.id)}
            onClick={() => { setSelectedGame(game); setResult(null); }}>
            <span style={styles.gameIcon}>{game.icon}</span>
            <div style={styles.gameName}>{game.name}</div>
            <div style={styles.gameCategory}>{game.category}</div>
            {game.category === 'PG Style' && <div className="badge-new">POPULAR</div>}
          </div>
        ))}
      </div>

      {selectedGame && (
        <div style={styles.playArea(selectedGame)}>
          <div style={{ position: 'absolute', top: '20px', left: '20px', color: getGameThemeColor(selectedGame), fontWeight: 800 }}>
            {selectedGame.name.toUpperCase()}
          </div>

          <div style={styles.reelsContainer}>
            {[1, 2, 3].map(i => (
              <div key={i} className={playing ? 'reel-spin' : ''} style={styles.reel}>
                {playing ? '❓' : (result?.winAmount > 0 ? selectedGame.icon : selectedGame.icon)}
              </div>
            ))}
          </div>

          <div style={{ marginBottom: '30px' }}>
            <p style={{ color: '#888', marginBottom: '15px' }}>VALOR DA APOSTA</p>
            <div style={styles.betControls}>
              {[5, 10, 20, 50, 100, 200].map(v => (
                <button key={v} style={styles.betBtn(betAmount === v)} onClick={() => setBetAmount(v)}>R$ {v}</button>
              ))}
            </div>
            <input type="number" value={betAmount} onChange={(e) => setBetAmount(e.target.value)} 
              style={{ background: '#0a0a0a', border: '1px solid #333', color: '#fff', padding: '12px', borderRadius: '10px', width: '150px', textAlign: 'center', fontSize: '18px', fontWeight: 700 }} />
          </div>

          <button className="btn-play" onClick={playGame} disabled={playing}
            style={{ padding: '20px 60px', fontSize: '20px', borderRadius: '50px', background: `linear-gradient(135deg, ${getGameThemeColor(selectedGame)}, #000)`, color: '#fff', border: 'none', cursor: 'pointer', fontWeight: 900, boxShadow: `0 0 20px ${getGameThemeColor(selectedGame)}44` }}>
            {playing ? 'GIRANDO...' : 'SOLTAR O TIGRE 🚀'}
          </button>

          {result && !playing && (
            <div style={{ marginTop: '30px', animation: 'bounceIn 0.5s' }}>
              <h2 style={{ color: result.winAmount > 0 ? '#00c853' : '#ff1744', fontSize: '24px', fontWeight: 900 }}>{result.message}</h2>
              {result.winAmount > 0 && (
                <div style={{ fontSize: '40px', color: '#FFD700', fontWeight: 900, textShadow: '0 0 20px rgba(255,215,0,0.5)' }}>
                  + R$ {result.winAmount.toFixed(2)}
                </div>
              )}
              <p style={{ color: '#888', marginTop: '10px' }}>Saldo atualizado: R$ {result.newBalance?.toFixed(2)}</p>
            </div>
          )}
        </div>
      )}

      <style>{`
        .badge-new { position: absolute; top: 10px; right: -20px; background: #ff1744; color: #fff; padding: 2px 25px; font-size: 8px; font-weight: 900; transform: rotate(45deg); }
        .reel-spin { animation: reelSpin 0.1s infinite; }
        @keyframes reelSpin { 0% { transform: translateY(-5px); } 50% { transform: translateY(5px); } 100% { transform: translateY(-5px); } }
        @keyframes bounceIn { 0% { transform: scale(0.3); opacity: 0; } 50% { transform: scale(1.05); opacity: 1; } 70% { transform: scale(0.9); } 100% { transform: scale(1); } }
        .btn-play:hover { transform: scale(1.05); filter: brightness(1.2); transition: 0.2s; }
        .btn-play:active { transform: scale(0.95); }
        .gold-text { color: #FFD700; text-shadow: 0 0 10px rgba(255,215,0,0.3); }
      `}</style>
    </div>
  );
};

export default Casino;
